mapper.select:
SELECT COUNT(*) > 0
FROM comment_likes
WHERE user_id = #{userId}
  AND comment_id = #{commentId}

mapper.delete:
DELETE FROM comment_likes
WHERE user_id = #{userId}
  AND comment_id = #{commentId}

mapper.select:
SELECT COUNT(*) FROM (
    SELECT c.id
    FROM comments c
    INNER JOIN posts p ON c.post_id = p.id
    WHERE p.user_id = #{userId}
      AND c.user_id != #{userId}
      AND c.status = 1
      AND c.parent_id IS NULL

    UNION ALL

    SELECT c.id
    FROM comments c
    WHERE c.reply_to_user_id = #{userId}
      AND c.user_id != #{userId}
      AND c.status = 1
) AS comment_notifications
